First, make sure you have Node.js installed on your machine. Then, create a new folder for your bot and navigate to it in your terminal.

Next, initialize a new Node.js project by running the following command:
```
npm init -y
```
This will create a `package.json` file in your project folder.

Next, install the Discord.js library by running the following command:
```
npm install discord.js
```
This will create a `node_modules` folder in your project folder and install the Discord.js library.

Next, create a new file in your project folder called `bot.js` and add the following code:
```javascript
const { Client, Collection, GatewayIntentBits } = require('discord.js');
const { token } = require('./config.json');

const client = new Client({ intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMessages, GatewayIntentBits.MessageContent, GatewayIntentBits.GuildMembers] });

client.commands = new Collection();

const commandFiles = ['ban.js'];

for (const file of commandFiles) {
  const command = require(`./commands/${file}`);
  client.commands.set(command.data.name, command);
}

client.once('ready', () => {
  console.log(`Ready! Logged in as ${client.user.tag}`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const command = client.commands.get(interaction.commandName);

  if (!command) return;

  try {
    await command.execute(interaction);
  } catch (error) {
    console.error(error);
    await interaction.reply({ content: 'There was an error trying to execute that command!', ephemeral: true });
  }
});

client.login(token);
```
This code sets up a new Discord.js client and loads the `ban` command from the `commands` folder.

Next, create a new folder in your project folder called `commands` and create a new file in that folder called `ban.js`. Add the following code to that file:
```javascript
const { SlashCommandBuilder } = require('discord.js');

module.exports = {
  data: new SlashCommandBuilder()
   .setName('ban')
   .setDescription('Bans a user from the server.')
   .addUserOption(option =>
      option.setName('user')
       .setDescription('The user to ban.')
       .setRequired(true)
    )
   .addStringOption(option =>
      option.setName('reason')
       .setDescription('The reason for the ban.')
       .setRequired(false)
    ),
  async execute(interaction) {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided.';

    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return await interaction.reply({ content: 'You do not have permission to ban users.', ephemeral: true });
    }

    if (user.id === interaction.user.id) {
      return await interaction.reply({ content: 'You cannot ban yourself.', ephemeral: true });
    }

    const member = interaction.guild.members.cache.get(user.id);

    if (!member) {
      return await interaction.reply({ content: 'That user is not a member of this server.', ephemeral: true });
    }

    if (!member.bannable) {
      return await interaction.reply({ content: 'I do not have permission to ban that user.', ephemeral: true });
    }

    await member.ban({ reason: reason });
    await interaction.reply({ content: `Successfully banned ${user.tag}.`, ephemeral: true });
  },
};
```
This code defines the `ban` command and its options, as well as the `execute` function that will be called when the command is run.

Finally, create a new file in your project folder called `config.json` and add the following code:
```json
{
  "token": "your_bot_token_here"
}
```
Replace `your_bot_token_here` with the token for your Discord bot.

That's it! You can now start your bot by running the following command in your terminal:
```
node bot.js
```
Your bot should now be online and ready to accept slash commands. To test the `ban` command, open your Discord server and type `/ban @username` (replace `username` with the name of the user you want to ban). You should see a prompt asking for the reason for the ban. Once you provide a reason, the user should be banned from the server.

